  private void createIdeaApplication() {
    if (LOG.isInfoLevel()) {
      LOG.info("Creating IdeaCmdApplication");
    }
    final String PERF_LOG_KEY = "idea.log.perf.stats";
    if (System.getProperty(PERF_LOG_KEY) == null) {
      // see StartUpPerformanceReporter.kt/logStats, which logs statistics when App.isInternal (our case). 
      // I doubt there's any reason for an end-user to see this statistics in a regular MPS scenario. Still, they could opt to do so with system property explicitly set.
      System.setProperty(PERF_LOG_KEY, Boolean.FALSE.toString());
    }
    System.setProperty("ide.new.project.model", Boolean.toString(false));
    System.setProperty("ide.open.readme.md.on.startup", Boolean.toString(false));
    if (System.getProperty(PathManager.PROPERTY_PATHS_SELECTOR) == null) {
      String val = "MPSCmdLine";
      if (myConfig.isTestMode()) {
        val += "Test";
      }
      System.setProperty(PathManager.PROPERTY_PATHS_SELECTOR, val);
    }
    String oldValue = System.getProperty(IDEA_USE_CORE_CL);
    if (oldValue == null) {
      // always true, resorting to the default behavior loading plugins from cp [apyshkin]
      System.setProperty(IDEA_USE_CORE_CL, Boolean.TRUE.toString());
    }
    if (myConfig.isTestMode()) {
      // Circumvent JBUIScale.computeSystemScaleFactor "Must be precomputed" error in tests
      System.setProperty("hidpi", Boolean.FALSE.toString());
      // Force GraphicsEnvironment to cache headless false state before TestApplicationManager resets it to true
      System.setProperty("java.awt.headless", Boolean.FALSE.toString());
      GraphicsEnvironment.isHeadless();
      System.setProperty("java.awt.headless", Boolean.TRUE.toString());
      myIdeaApplication = TestApplicationManager.getInstance();
    } else {
      myIdeaApplication = MPSHeadlessPlatformStarter.Holder.IT.createApp();
    }
  }

